"use strict";
Object.defineProperty(exports, "__esModule", { value: true });
const path_1 = require("path");
const file = path_1.join(__dirname, 'file.txt');
```

[Output TS 4.4 or newer](https://www.typescriptlang.org/play?target=6&module=1&ts=4.4.4#code/JYWwDg9gTgLgBAbzgKwsAdnAvnAZlCEOAcjAEMYALYgKBoGMJ0BneXYAGwFM4BeFNOgAUAfREATYFHRkQXADQl23AHQwAHjGIBKIA):

```js
"use strict";
Object.defineProperty(exports, "__esModule", { value: true });
const path_1 = require("path");
const file = (0, path_1.join)(__dirname, 'file.txt');
```

